function normalizeIntent(value) {
  const normalized = asString(value)?.toLowerCase();
  return ['buy', 'sell', 'rent', 'unknown'].includes(normalized) ? normalized : 'unknown';
}

function normalizeStringArray(value) {
  const input = Array.isArray(value) ? value : [value];
  const seen = new Set();
  const output = [];

  for (const entry of input.flat()) {
    const normalized = asString(entry);
    if (!normalized) continue;
    const key = normalized.toLowerCase();
    if (seen.has(key)) continue;
    seen.add(key);
    output.push(normalized);
  }

  return output;
}

function toNumber(value) {
  if (value === null || value === undefined || value === '') return null;
  const normalized = Number(value);
  return Number.isFinite(normalized) ? normalized : null;
}

function toNullableBoolean(value) {
  if (value === null || value === undefined || value === '') return null;
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value === 1 ? true : value === 0 ? false : null;
  const normalized = String(value).trim().toLowerCase();
  if (['true', 'sim', 'yes', '1'].includes(normalized)) return true;
  if (['false', 'nao', 'no', '0'].includes(normalized)) return false;
  return null;
}

function normalizeTextKey(value) {
  const normalized = asString(value);
  if (!normalized) return null;
  return normalized
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase();
}

function normalizePropertyType(value) {
  const normalized = normalizeTextKey(value);
  if (!normalized) return null;

  if (normalized.includes('apartamento') || normalized.includes('apto') || normalized.includes('flat') || normalized.includes('studio') || normalized.includes('kitnet') || normalized.includes('cobertura') || normalized.includes('duplex')) {
    return 'apartamento';
  }

  if (normalized.includes('casa') || normalized.includes('sobrado') || normalized.includes('townhouse') || normalized.includes('vila')) {
    return 'casa';
  }

  if (normalized.includes('terreno') || normalized.includes('lote')) {
    return 'terreno';
  }

  if (normalized.includes('comercial') || normalized.includes('sala') || normalized.includes('galpao') || normalized.includes('loja')) {
    return 'comercial';
  }

  if (normalized.includes('chacara') || normalized.includes('sitio') || normalized.includes('fazenda')) {
    return 'rural';
  }

  return normalized;
}

